// Tab-completion for the in-browser shell line editor (WeNodeTerminal).
// Currently: `cd` directory completion against MemoryVolume.

import type { MemoryVolume } from "../memory-volume";

const DEFAULT_HOME = "/home/user";

function normalizeAbs(raw: string): string {
  const parts = raw.split("/").filter(Boolean);
  const stack: string[] = [];
  for (const part of parts) {
    if (part === "..") stack.pop();
    else if (part !== ".") stack.push(part);
  }
  return "/" + stack.join("/");
}

function resolveDir(cwd: string, dirFrag: string): string {
  const frag = dirFrag.trim();
  if (!frag || frag === ".") return normalizeAbs(cwd);
  if (frag === "/") return "/";
  if (frag.startsWith("/")) return normalizeAbs(frag);
  return normalizeAbs(`${cwd}/${frag}`);
}

function expandTildeInFragment(pathFrag: string, home: string): string {
  const s = pathFrag;
  if (s === "~" || s.startsWith("~/")) return home + s.slice(1);
  return s;
}

function splitDirAndPartial(pathFrag: string): { dirFrag: string; partial: string } {
  let s = pathFrag.replace(/^\s+/, "").replace(/\s+$/, "");
  if (!s) return { dirFrag: "", partial: "" };

  if (s.endsWith("/")) {
    const d = s.replace(/\/+$/, "");
    return { dirFrag: d === "" ? "/" : d, partial: "" };
  }

  const i = s.lastIndexOf("/");
  if (i === -1) return { dirFrag: "", partial: s };
  if (i === 0 && s.startsWith("/")) {
    return { dirFrag: "/", partial: s.slice(1) };
  }
  return { dirFrag: s.slice(0, i), partial: s.slice(i + 1) };
}

function commonPrefix(items: string[]): string {
  if (items.length === 0) return "";
  let prefix = items[0] ?? "";
  for (let k = 1; k < items.length; k++) {
    const s = items[k] ?? "";
    let j = 0;
    while (j < prefix.length && j < s.length && prefix[j] === s[j]) j++;
    prefix = prefix.slice(0, j);
    if (!prefix) break;
  }
  return prefix;
}

function isDirEntry(volume: MemoryVolume, dir: string, name: string): boolean {
  const full = `${dir}/${name}`.replace(/\/+/g, "/");
  try {
    return volume.statSync(full).isDirectory();
  } catch {
    return false;
  }
}

function completeCdPath(
  volume: MemoryVolume,
  cwd: string,
  pathFragment: string,
  home: string,
): string {
  const expanded = expandTildeInFragment(pathFragment, home);
  const { dirFrag, partial } = splitDirAndPartial(expanded);
  const resolvedDir = resolveDir(cwd, dirFrag);

  if (!volume.existsSync(resolvedDir)) return "";

  let names: string[];
  try {
    names = volume.readdirSync(resolvedDir);
  } catch {
    return "";
  }

  const dirs = names
    .filter((n) => isDirEntry(volume, resolvedDir, n))
    .filter((n) => n.startsWith(partial))
    .sort();

  if (dirs.length === 0) return "";

  const prefix = commonPrefix(dirs);
  let insert = prefix.slice(partial.length);

  if (dirs.length === 1) {
    insert += "/";
  }

  return insert;
}

/**
 * Returns text to insert at the end of `line` (cursor-at-end model).
 */
export function tabCompleteShellLine(
  volume: MemoryVolume,
  line: string,
  cwd: string,
  opts?: { home?: string },
): string {
  const home = opts?.home ?? DEFAULT_HOME;

  const trimmedEnd = line.trimEnd();
  if (/^\s*cd$/i.test(trimmedEnd) && line.length === trimmedEnd.length) {
    return " ";
  }

  const cdLead = line.match(/^\s*cd(\s+)(.*)$/i);
  if (cdLead) {
    const pathFragment = cdLead[2] ?? "";
    return completeCdPath(volume, cwd, pathFragment, home);
  }

  return "";
}
