import type { VolumeSnapshot } from "../engine-types";
import type { MemoryVolume } from "../memory-volume";

export interface OPFSPersistenceOptions {
  /**
   * Directory under OPFS root used by weNode.
   * Nested paths like "weNode/workspace-a" are supported.
   */
  rootDir?: string;
  /**
   * Snapshot file name stored under rootDir.
   */
  snapshotFile?: string;
}

interface OPFSFileHandle {
  getFile(): Promise<{ text(): Promise<string>; arrayBuffer(): Promise<ArrayBuffer> }>;
  createWritable(): Promise<{ write(data: string | Uint8Array): Promise<void>; close(): Promise<void> }>;
}

interface OPFSDirectoryHandle {
  getDirectoryHandle(name: string, opts?: { create?: boolean }): Promise<OPFSDirectoryHandle>;
  getFileHandle(name: string, opts?: { create?: boolean }): Promise<OPFSFileHandle>;
  removeEntry(name: string, opts?: { recursive?: boolean }): Promise<void>;
  entries(): AsyncIterable<[string, OPFSDirectoryHandle | OPFSFileHandle]>;
}

const DEFAULT_ROOT_DIR = "weNode";
const DEFAULT_SNAPSHOT_FILE = "volume.snapshot.json";
const FILES_DIR = "fs";
const TARBALLS_DIR = "tarballs";
const METADATA_DIR = "registry-metadata";

function getStorageManager(): { getDirectory?: () => Promise<OPFSDirectoryHandle> } | null {
  if (typeof navigator === "undefined") return null;
  const storage = (navigator as unknown as { storage?: { getDirectory?: () => Promise<OPFSDirectoryHandle> } }).storage;
  return storage ?? null;
}

async function resolveRootDirectory(
  opts?: OPFSPersistenceOptions,
): Promise<OPFSDirectoryHandle | null> {
  const storage = getStorageManager();
  if (!storage || typeof storage.getDirectory !== "function") return null;

  const root = await storage.getDirectory();
  const rootDir = (opts?.rootDir ?? DEFAULT_ROOT_DIR).trim();
  if (!rootDir) return root;

  const segments = rootDir.split("/").filter(Boolean);
  let dir = root;
  for (const segment of segments) {
    dir = await dir.getDirectoryHandle(segment, { create: true });
  }
  return dir;
}

async function resolveSubDirectory(
  root: OPFSDirectoryHandle,
  subPath: string,
  create: boolean,
): Promise<OPFSDirectoryHandle> {
  const segments = subPath.split("/").filter(Boolean);
  let dir = root;
  for (const segment of segments) {
    dir = await dir.getDirectoryHandle(segment, { create });
  }
  return dir;
}

function toSegments(path: string): string[] {
  if (!path || path === "/") return [];
  return path.split("/").filter(Boolean);
}

function tarballKeyFromUrl(url: string): string {
  let hash = 2166136261 >>> 0;
  for (let i = 0; i < url.length; i++) {
    hash ^= url.charCodeAt(i);
    hash = Math.imul(hash, 16777619) >>> 0;
  }
  return `tarball-${hash.toString(16)}.tgz`;
}

function metadataKeyFromPackage(registryUrl: string, packageName: string): string {
  const source = `${registryUrl}|${packageName}`;
  let hash = 2166136261 >>> 0;
  for (let i = 0; i < source.length; i++) {
    hash ^= source.charCodeAt(i);
    hash = Math.imul(hash, 16777619) >>> 0;
  }
  return `manifest-${hash.toString(16)}.json`;
}

function getSnapshotFileName(opts?: OPFSPersistenceOptions): string {
  const file = (opts?.snapshotFile ?? DEFAULT_SNAPSHOT_FILE).trim();
  return file || DEFAULT_SNAPSHOT_FILE;
}

function isNotFoundError(err: unknown): boolean {
  return !!err && typeof err === "object" && (err as { name?: string }).name === "NotFoundError";
}

function isValidSnapshot(raw: unknown): raw is VolumeSnapshot {
  if (!raw || typeof raw !== "object") return false;
  return Array.isArray((raw as { entries?: unknown[] }).entries);
}

export function isOPFSAvailable(): boolean {
  const storage = getStorageManager();
  return !!storage && typeof storage.getDirectory === "function";
}

async function getFilesRoot(
  opts?: OPFSPersistenceOptions,
  create: boolean = true,
): Promise<OPFSDirectoryHandle | null> {
  const root = await resolveRootDirectory(opts);
  if (!root) return null;
  try {
    return await root.getDirectoryHandle(FILES_DIR, { create });
  } catch (err) {
    if (isNotFoundError(err)) return null;
    throw err;
  }
}

async function ensureParentDir(
  filesRoot: OPFSDirectoryHandle,
  path: string,
): Promise<OPFSDirectoryHandle> {
  const parts = toSegments(path);
  if (parts.length <= 1) return filesRoot;
  const dirParts = parts.slice(0, parts.length - 1);
  let dir = filesRoot;
  for (const part of dirParts) {
    dir = await dir.getDirectoryHandle(part, { create: true });
  }
  return dir;
}

async function removePathFromOPFS(
  filesRoot: OPFSDirectoryHandle,
  path: string,
): Promise<void> {
  const parts = toSegments(path);
  if (parts.length === 0) return;

  let dir = filesRoot;
  for (let i = 0; i < parts.length - 1; i++) {
    try {
      dir = await dir.getDirectoryHandle(parts[i], { create: false });
    } catch (err) {
      if (isNotFoundError(err)) return;
      throw err;
    }
  }

  try {
    await dir.removeEntry(parts[parts.length - 1], { recursive: true });
  } catch (err) {
    if (isNotFoundError(err)) return;
    throw err;
  }
}

export async function hydrateVolumeFromOPFS(
  volume: MemoryVolume,
  opts?: OPFSPersistenceOptions,
): Promise<boolean> {
  const filesRoot = await getFilesRoot(opts, false);
  if (!filesRoot) return false;

  let hydratedAny = false;
  const stack: Array<{ dir: OPFSDirectoryHandle; path: string }> = [{ dir: filesRoot, path: "/" }];

  while (stack.length > 0) {
    const current = stack.pop()!;
    for await (const [name, handle] of current.dir.entries()) {
      const fullPath = current.path === "/" ? `/${name}` : `${current.path}/${name}`;
      const kind = (handle as { kind?: string }).kind;
      if (kind === "directory") {
        if (!volume.existsSync(fullPath)) {
          volume.mkdirSync(fullPath, { recursive: true });
        }
        hydratedAny = true;
        stack.push({ dir: handle as OPFSDirectoryHandle, path: fullPath });
      } else if (kind === "file") {
        const file = await (handle as OPFSFileHandle).getFile();
        const bytes = new Uint8Array(await file.arrayBuffer());
        volume.writeFileSync(fullPath, bytes);
        hydratedAny = true;
      }
    }
  }

  return hydratedAny;
}

export async function syncPathToOPFS(
  volume: MemoryVolume,
  path: string,
  opts?: OPFSPersistenceOptions,
): Promise<void> {
  if (!path || path === "/") return;
  const filesRoot = await getFilesRoot(opts, true);
  if (!filesRoot) return;

  if (!volume.existsSync(path)) {
    await removePathFromOPFS(filesRoot, path);
    return;
  }

  const stat = volume.statSync(path);
  if (stat.isDirectory()) {
    const parts = toSegments(path);
    let dir = filesRoot;
    for (const part of parts) {
      dir = await dir.getDirectoryHandle(part, { create: true });
    }
    return;
  }

  const parent = await ensureParentDir(filesRoot, path);
  const parts = toSegments(path);
  const fileName = parts[parts.length - 1];
  const fileHandle = await parent.getFileHandle(fileName, { create: true });
  const writable = await fileHandle.createWritable();
  const bytes = volume.readFileSync(path);
  await writable.write(bytes);
  await writable.close();
}

// Maximum number of concurrent OPFS file-write operations.
// Too high risks hitting browser concurrency limits; 16 is a safe sweet-spot.
const OPFS_WRITE_CONCURRENCY = 16;

export async function syncEntireVolumeToOPFS(
  volume: MemoryVolume,
  opts?: OPFSPersistenceOptions,
  startPath: string = "/",
): Promise<void> {
  const filesRoot = await getFilesRoot(opts, true);
  if (!filesRoot) return;

  // Phase 1: collect every file path via a synchronous in-memory BFS.
  // This is cheap — no async I/O involved.
  const filePaths: string[] = [];
  const stack: string[] = [startPath];
  while (stack.length > 0) {
    const dir = stack.pop()!;
    let entries: string[];
    try {
      entries = volume.readdirSync(dir) as string[];
    } catch {
      continue;
    }
    for (const name of entries) {
      const full = dir === "/" ? `/${name}` : `${dir}/${name}`;
      try {
        if (volume.statSync(full).isDirectory()) {
          stack.push(full);
        } else {
          filePaths.push(full);
        }
      } catch {
        // skip inaccessible entries
      }
    }
  }

  // Phase 2: write all files in parallel batches.
  //
  // Directory handles are resolved via a promise-keyed cache so that:
  //  - concurrent writes to the same directory share one getDirectoryHandle call
  //  - parent directories are always resolved before their children (chain via .then)
  //  - the OPFS root is fetched only once (above)
  const dirCache = new Map<string, Promise<OPFSDirectoryHandle>>();

  function resolveDir(segments: string[]): Promise<OPFSDirectoryHandle> {
    const key = segments.join("/");
    const hit = dirCache.get(key);
    if (hit) return hit;
    let p: Promise<OPFSDirectoryHandle>;
    if (segments.length === 0) {
      p = Promise.resolve(filesRoot);
    } else {
      const parentPromise = resolveDir(segments.slice(0, -1));
      const name = segments[segments.length - 1];
      p = parentPromise.then((d) => d.getDirectoryHandle(name, { create: true }));
    }
    dirCache.set(key, p);
    return p;
  }

  async function writeOne(filePath: string): Promise<void> {
    try {
      const parts = toSegments(filePath);
      const fileName = parts[parts.length - 1];
      const parentDir = await resolveDir(parts.slice(0, -1));
      const fh = await parentDir.getFileHandle(fileName, { create: true });
      const writable = await fh.createWritable();
      await writable.write(volume.readFileSync(filePath));
      await writable.close();
    } catch {
      // best-effort — skip individual file errors
    }
  }

  for (let i = 0; i < filePaths.length; i += OPFS_WRITE_CONCURRENCY) {
    await Promise.all(
      filePaths.slice(i, i + OPFS_WRITE_CONCURRENCY).map(writeOne),
    );
  }
}

export async function readTarballFromOPFS(
  url: string,
  opts?: OPFSPersistenceOptions,
): Promise<Uint8Array | null> {
  const root = await resolveRootDirectory(opts);
  if (!root) return null;
  let dir: OPFSDirectoryHandle;
  try {
    dir = await root.getDirectoryHandle(TARBALLS_DIR, { create: false });
  } catch (err) {
    if (isNotFoundError(err)) return null;
    throw err;
  }

  try {
    const fh = await dir.getFileHandle(tarballKeyFromUrl(url), { create: false });
    const file = await fh.getFile();
    return new Uint8Array(await file.arrayBuffer());
  } catch (err) {
    if (isNotFoundError(err)) return null;
    throw err;
  }
}

export async function writeTarballToOPFS(
  url: string,
  data: Uint8Array,
  opts?: OPFSPersistenceOptions,
): Promise<void> {
  const root = await resolveRootDirectory(opts);
  if (!root) return;
  const dir = await root.getDirectoryHandle(TARBALLS_DIR, { create: true });
  const fh = await dir.getFileHandle(tarballKeyFromUrl(url), { create: true });
  const writable = await fh.createWritable();
  await writable.write(data);
  await writable.close();
}

export async function readRegistryMetadataFromOPFS(
  registryUrl: string,
  packageName: string,
  opts?: OPFSPersistenceOptions,
): Promise<string | null> {
  const root = await resolveRootDirectory(opts);
  if (!root) return null;
  let dir: OPFSDirectoryHandle;
  try {
    dir = await root.getDirectoryHandle(METADATA_DIR, { create: false });
  } catch (err) {
    if (isNotFoundError(err)) return null;
    throw err;
  }

  try {
    const fh = await dir.getFileHandle(
      metadataKeyFromPackage(registryUrl, packageName),
      { create: false },
    );
    const file = await fh.getFile();
    return await file.text();
  } catch (err) {
    if (isNotFoundError(err)) return null;
    throw err;
  }
}

export async function writeRegistryMetadataToOPFS(
  registryUrl: string,
  packageName: string,
  data: string,
  opts?: OPFSPersistenceOptions,
): Promise<void> {
  const root = await resolveRootDirectory(opts);
  if (!root) return;
  const dir = await root.getDirectoryHandle(METADATA_DIR, { create: true });
  const fh = await dir.getFileHandle(
    metadataKeyFromPackage(registryUrl, packageName),
    { create: true },
  );
  const writable = await fh.createWritable();
  await writable.write(data);
  await writable.close();
}

export async function loadSnapshotFromOPFS(
  opts?: OPFSPersistenceOptions,
): Promise<VolumeSnapshot | null> {
  const dir = await resolveRootDirectory(opts);
  if (!dir) return null;

  try {
    const fileHandle = await dir.getFileHandle(getSnapshotFileName(opts), { create: false });
    const file = await fileHandle.getFile();
    const text = await file.text();
    if (!text.trim()) return null;
    const parsed = JSON.parse(text);
    if (!isValidSnapshot(parsed)) return null;
    return parsed;
  } catch (err) {
    if (isNotFoundError(err)) return null;
    throw err;
  }
}

export async function saveSnapshotToOPFS(
  snapshot: VolumeSnapshot,
  opts?: OPFSPersistenceOptions,
): Promise<void> {
  const dir = await resolveRootDirectory(opts);
  if (!dir) return;
  const fileHandle = await dir.getFileHandle(getSnapshotFileName(opts), { create: true });
  const writable = await fileHandle.createWritable();
  await writable.write(JSON.stringify(snapshot));
  await writable.close();
}
