// Dependency Installer
// Handles the full install lifecycle: resolve, download, extract, transform, bin stubs, lock file.

import { MemoryVolume } from "../memory-volume";
import {
  hydrateVolumeFromOPFS,
  readRegistryMetadataFromOPFS,
  syncEntireVolumeToOPFS,
  syncPathToOPFS,
  writeRegistryMetadataToOPFS,
} from "../sdk/opfs-snapshot-store";
import { RegistryClient, RegistryConfig } from "./registry-client";
import {
  resolveDependencyTree,
  resolveFromManifest,
  ResolvedDependency,
  ResolutionConfig,
} from "./version-resolver";
import { downloadAndExtract } from "./archive-extractor";
import { convertPackage, prepareTransformer } from "../module-transformer";
import type { PackageManifest } from "../types/manifest";
import * as path from "../polyfills/path";

// ---------------------------------------------------------------------------
// Public types
// ---------------------------------------------------------------------------

export interface InstallFlags {
  registry?: string;
  persist?: boolean;
  persistDev?: boolean;
  withDevDeps?: boolean;
  withOptionalDeps?: boolean;
  onProgress?: (message: string) => void;
  // default: true
  transformModules?: boolean;
}

export interface InstallOutcome {
  resolved: Map<string, ResolvedDependency>;
  newPackages: string[];
}

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

// Normalize bin field — handles both shorthand string and object forms
function normalizeBinField(
  packageName: string,
  bin?: string | Record<string, string>,
): Record<string, string> {
  if (!bin) return {};
  if (typeof bin === "string") {
    const command = packageName.includes("/")
      ? packageName.split("/").pop()!
      : packageName;
    return { [command]: bin };
  }
  return bin;
}

// Split "express@4.18.2" or "@types/node@20" into name + version
function splitSpecifier(spec: string): { name: string; version?: string } {
  if (spec.startsWith("@")) {
    const slashIdx = spec.indexOf("/");
    if (slashIdx === -1)
      throw new Error(`Malformed package specifier: ${spec}`);

    const tail = spec.slice(slashIdx + 1);
    const atIdx = tail.indexOf("@");
    if (atIdx === -1) return { name: spec };
    return {
      name: spec.slice(0, slashIdx + 1 + atIdx),
      version: tail.slice(atIdx + 1),
    };
  }

  const atIdx = spec.indexOf("@");
  if (atIdx === -1) return { name: spec };
  return {
    name: spec.slice(0, atIdx),
    version: spec.slice(atIdx + 1),
  };
}

// ---------------------------------------------------------------------------
// Main class
// ---------------------------------------------------------------------------

let transformerReady = false;
const INSTALL_STAMP_NAMESPACE = "nodepod-install-stamp";
const OPFS_TIMEOUT_MS = 3500;

export class DependencyInstaller {
  private vol: MemoryVolume;
  private registryClient: RegistryClient;
  private workingDir: string;

  constructor(vol: MemoryVolume, opts: { cwd?: string } & RegistryConfig = {}) {
    this.vol = vol;
    this.registryClient = new RegistryClient(opts);
    this.workingDir = opts.cwd || "/";
  }

  // -----------------------------------------------------------------------
  // Public API
  // -----------------------------------------------------------------------

  async install(
    packageName: string,
    version?: string,
    flags: InstallFlags = {},
  ): Promise<InstallOutcome> {
    const { onProgress } = flags;

    const spec = splitSpecifier(packageName);
    const targetName = spec.name;
    const targetRange = version || spec.version || "latest";

    onProgress?.(`Resolving ${targetName}@${targetRange}...`);

    const resolutionOpts: ResolutionConfig = {
      registry: this.registryClient,
      devDependencies: flags.withDevDeps,
      optionalDependencies: flags.withOptionalDeps,
      onProgress,
    };

    const tree = await resolveDependencyTree(
      targetName,
      targetRange,
      resolutionOpts,
    );

    const newPkgs = await this.materializePackages(tree, flags);

    if (flags.persist || flags.persistDev) {
      const entry = tree.get(targetName);
      if (entry) {
        await this.patchManifest(
          targetName,
          `^${entry.version}`,
          !!flags.persistDev,
        );
      }
    }

    // Persist newly installed packages to OPFS so page refresh doesn't lose them.
    // Also invalidates the manifest-based stamp so installFromManifest will
    // re-hydrate correctly on the next cold start.
    await this.syncNewPackagesToOPFS(newPkgs, onProgress);

    onProgress?.(`Installed ${tree.size} package(s)`);

    return { resolved: tree, newPackages: newPkgs };
  }

  async installFromManifest(
    manifestPath?: string,
    flags: InstallFlags = {},
  ): Promise<InstallOutcome> {
    const { onProgress } = flags;

    const jsonPath = manifestPath || path.join(this.workingDir, "package.json");

    if (!this.vol.existsSync(jsonPath)) {
      throw new Error(`Manifest not found at ${jsonPath}`);
    }

    const raw = this.vol.readFileSync(jsonPath, "utf8");
    const manifest: PackageManifest = JSON.parse(raw);

    // Lock-first fast path:
    // - if OPFS stamp matches current manifest, hydrate and skip install
    // - if no stamp, fall back to normal resolver/install flow
    const stamp = this.computeManifestStamp(manifest, !!flags.withDevDeps);
    const stampHit = await this.readInstallStampSafe();
    onProgress?.(
      `Install stamp check: expected=${stamp.slice(0, 12)}... got=${stampHit ? `${stampHit.slice(0, 12)}...` : "none"}`,
    );
    if (stampHit === stamp) {
      const hydrated = await this.hydrateFromOpfsSafe();
      onProgress?.(`Install stamp hydrate: ${hydrated ? "ok" : "empty"}`);
      if (hydrated) {
        onProgress?.("Reused OPFS install stamp (fast path)");
        return { resolved: new Map(), newPackages: [] };
      }
    }

    onProgress?.("Resolving dependency tree...");

    const resolutionOpts: ResolutionConfig = {
      registry: this.registryClient,
      devDependencies: flags.withDevDeps,
      optionalDependencies: flags.withOptionalDeps,
      onProgress,
    };

    const tree = await resolveFromManifest(manifest, resolutionOpts);

    // 获取直接依赖信息
    const allDeps: Record<string, string> = { ...manifest.dependencies };
    if (flags.withDevDeps && manifest.devDependencies) {
      Object.assign(allDeps, manifest.devDependencies);
    }
    const directDeps = new Map(Object.entries(allDeps));

    const newPkgs = await this.materializePackages(tree, flags, directDeps);

    // Persist full VFS and install stamp best-effort.
    await this.syncOpfsAndStampSafe(stamp, onProgress);

    onProgress?.(`Installed ${tree.size} package(s)`);

    return { resolved: tree, newPackages: newPkgs };
  }

  listInstalled(): Record<string, string> {
    const nmDir = path.join(this.workingDir, "node_modules");
    if (!this.vol.existsSync(nmDir)) return {};

    const result: Record<string, string> = {};
    const topLevel = this.vol.readdirSync(nmDir) as string[];

    for (const entry of topLevel) {
      if (entry.startsWith(".")) continue;

      if (entry.startsWith("@")) {
        const scopeDir = path.join(nmDir, entry);
        const scopedEntries = this.vol.readdirSync(scopeDir) as string[];
        for (const child of scopedEntries) {
          const manifest = path.join(scopeDir, child, "package.json");
          if (this.vol.existsSync(manifest)) {
            const data = JSON.parse(this.vol.readFileSync(manifest, "utf8"));
            result[`${entry}/${child}`] = data.version;
          }
        }
      } else {
        const manifest = path.join(nmDir, entry, "package.json");
        if (this.vol.existsSync(manifest)) {
          const data = JSON.parse(this.vol.readFileSync(manifest, "utf8"));
          result[entry] = data.version;
        }
      }
    }

    return result;
  }

  // -----------------------------------------------------------------------
  // Private helpers
  // -----------------------------------------------------------------------

  // Download, extract, transform, and wire up packages not already in node_modules
  private async materializePackages(
    tree: Map<string, ResolvedDependency>,
    flags: InstallFlags,
    directDeps?: Map<string, string>, // 传递直接依赖信息，用于判断是否嵌套安装
  ): Promise<string[]> {
    const { onProgress } = flags;
    const additions: string[] = [];

    const nmRoot = path.join(this.workingDir, "node_modules");
    this.vol.mkdirSync(nmRoot, { recursive: true });

    const pending: Array<{
      depName: string;
      dep: ResolvedDependency;
      targetDir: string;
    }> = [];

    for (const [depKey, dep] of tree) {
      // 只针对 zod 包：处理 zod@version 格式的 key
      let depName = depKey;
      let targetDir = path.join(nmRoot, depName);
      
      if (depKey.startsWith("zod@")) {
        // 对于 zod，key 格式是 zod@version，但安装时使用 zod 作为包名
        depName = "zod";
        
        // 如果这个 zod 是传递依赖（有 parentPackage），安装到父包的 node_modules/zod 中
        // 直接依赖的 zod 不会有 parentPackage，所以会安装到根目录
        if (dep.parentPackage) {
          // 安装到父包的 node_modules/zod
          const parentPkgDir = path.join(nmRoot, dep.parentPackage);
          targetDir = path.join(parentPkgDir, "node_modules", depName);
        } else {
          // 直接依赖的 zod，安装到根目录
          targetDir = path.join(nmRoot, depName);
        }
      }
      
      const existingManifest = path.join(targetDir, "package.json");

      if (this.vol.existsSync(existingManifest)) {
        try {
          const current = JSON.parse(
            this.vol.readFileSync(existingManifest, "utf8"),
          );
          if (current.version === dep.version) {
            onProgress?.(`Skipping ${depName}@${dep.version} (up to date)`);
            continue;
          }
        } catch {
          // corrupt manifest, reinstall
        }
      }

      pending.push({ depName, dep, targetDir });
    }

    // Only need main-thread transformer as fallback when workers aren't available
    const shouldTransform = flags.transformModules !== false;
    if (shouldTransform && !transformerReady) {
      if (typeof Worker === "undefined") {
        onProgress?.("Preparing module transformer...");
        await prepareTransformer();
      }
      transformerReady = true;
    }

    // Safe to batch aggressively since extract + transform are offloaded to workers
    const WORKER_COUNT = 12;
    onProgress?.(`Downloading ${pending.length} package(s)...`);

    for (let offset = 0; offset < pending.length; offset += WORKER_COUNT) {
      const batch = pending.slice(offset, offset + WORKER_COUNT);

      await Promise.all(
        batch.map(async ({ depName, dep, targetDir }) => {
          onProgress?.(`  Fetching ${depName}@${dep.version}...`);

          await downloadAndExtract(dep.tarballUrl, this.vol, targetDir, {
            stripComponents: 1,
          });

          if (shouldTransform) {
            try {
              const transformed = await convertPackage(
                this.vol,
                targetDir,
                onProgress,
              );
              if (transformed > 0) {
                onProgress?.(
                  `  Transformed ${transformed} file(s) in ${depName}`,
                );
              }
            } catch (err) {
              onProgress?.(
                `  Warning: transformation failed for ${depName}: ${err}`,
              );
            }
          }

          this.createBinStubs(nmRoot, depName, targetDir);

          additions.push(depName);
        }),
      );
    }

    this.writeLockFile(tree);

    return additions;
  }

  private createBinStubs(
    nmRoot: string,
    depName: string,
    pkgDir: string,
  ): void {
    try {
      const manifestPath = path.join(pkgDir, "package.json");
      if (!this.vol.existsSync(manifestPath)) return;

      const data = JSON.parse(this.vol.readFileSync(manifestPath, "utf8"));
      const bins = normalizeBinField(depName, data.bin);
      const binDir = path.join(nmRoot, ".bin");

      for (const [cmd, relPath] of Object.entries(bins)) {
        this.vol.mkdirSync(binDir, { recursive: true });
        const target = path.join(pkgDir, relPath);
        this.vol.writeFileSync(
          path.join(binDir, cmd),
          `node "${target}" "$@"\n`,
        );
      }
    } catch {
      // best-effort
    }
  }

  private writeLockFile(tree: Map<string, ResolvedDependency>): void {
    const lockPath = path.join(
      this.workingDir,
      "node_modules",
      ".package-lock.json",
    );

    // Keep lock content cumulative so incremental installs do not drop
    // previously resolved runtime packages.
    const entries: Record<string, { version: string; resolved: string }> = {};
    if (this.vol.existsSync(lockPath)) {
      try {
        const raw = this.vol.readFileSync(lockPath, "utf8");
        const parsed = JSON.parse(raw) as Record<
          string,
          { version?: string; resolved?: string }
        >;
        for (const [name, meta] of Object.entries(parsed)) {
          if (meta?.version && meta?.resolved) {
            entries[name] = {
              version: meta.version,
              resolved: meta.resolved,
            };
          }
        }
      } catch {
        // ignore corrupt lock and rewrite with current data
      }
    }

    for (const [depName, dep] of tree) {
      entries[depName] = {
        version: dep.version,
        resolved: dep.tarballUrl,
      };
    }

    this.vol.writeFileSync(lockPath, JSON.stringify(entries, null, 2));
  }

  private computeManifestStamp(
    manifest: PackageManifest,
    includeDevDeps: boolean,
  ): string {
    const deps: Record<string, string> = { ...(manifest.dependencies || {}) };
    if (includeDevDeps && manifest.devDependencies) {
      Object.assign(deps, manifest.devDependencies);
    }
    const payload = JSON.stringify({
      cwd: this.workingDir,
      deps: Object.entries(deps).sort(([a], [b]) => a.localeCompare(b)),
    });
    let hash = 2166136261 >>> 0;
    for (let i = 0; i < payload.length; i++) {
      hash ^= payload.charCodeAt(i);
      hash = Math.imul(hash, 16777619) >>> 0;
    }
    return `v1:${hash.toString(16)}`;
  }

  private withTimeout<T>(promise: Promise<T>, ms: number, fallback: T): Promise<T> {
    return Promise.race([
      promise,
      new Promise<T>((resolve) => {
        setTimeout(() => resolve(fallback), ms);
      }),
    ]);
  }

  private async readInstallStampSafe(): Promise<string | null> {
    try {
      return await this.withTimeout(
        readRegistryMetadataFromOPFS(
          INSTALL_STAMP_NAMESPACE,
          this.workingDir || "/",
        ),
        OPFS_TIMEOUT_MS,
        null,
      );
    } catch {
      return null;
    }
  }

  private async hydrateFromOpfsSafe(): Promise<boolean> {
    try {
      const ok = await hydrateVolumeFromOPFS(this.vol);
      if (!ok) return false;
      // Verify integrity: if OPFS was written by old code that only persisted
      // directory entries (not file contents), the hydrated node_modules will
      // have empty dirs but no actual package files — treat as a miss.
      return this.verifyNodeModulesIntegrity();
    } catch {
      return false;
    }
  }

  private verifyNodeModulesIntegrity(): boolean {
    const nmDir = path.join(this.workingDir || "/", "node_modules");
    if (!this.vol.existsSync(nmDir)) return false;
    const lockPath = path.join(nmDir, ".package-lock.json");
    if (!this.vol.existsSync(lockPath)) return false;
    try {
      const lock = JSON.parse(
        this.vol.readFileSync(lockPath, "utf8"),
      ) as Record<string, unknown>;
      for (const key of Object.keys(lock)) {
        // Keys with ":parentPkg" are nested installs under another package — skip
        if (key.includes(":")) continue;
        // Derive the installation directory name from the key.
        // Normal keys:  "lodash", "@scope/pkg"
        // Versioned keys: "zod@^4.3.6" → install dir is "zod"
        let pkgName: string;
        if (key.startsWith("@")) {
          pkgName = key; // scoped package — no version suffix added by current code
        } else {
          const atIdx = key.indexOf("@");
          pkgName = atIdx === -1 ? key : key.slice(0, atIdx);
        }
        if (!this.vol.existsSync(path.join(nmDir, pkgName, "package.json"))) {
          return false;
        }
      }
      return true;
    } catch {
      return false;
    }
  }

  private async syncOpfsAndStampSafe(
    stamp: string,
    onProgress?: (message: string) => void,
  ): Promise<void> {
    try {
      await this.syncWorkingTreeToOPFS();
      await writeRegistryMetadataToOPFS(
        INSTALL_STAMP_NAMESPACE,
        this.workingDir || "/",
        stamp,
      );
      onProgress?.("Wrote OPFS install stamp");
    } catch (err) {
      const msg = err instanceof Error ? err.message : String(err);
      onProgress?.(`OPFS stamp skipped: ${msg}`);
    }
  }

  private async syncWorkingTreeToOPFS(): Promise<void> {
    const cwd = this.workingDir || "/";
    const pkgJson = path.join(cwd, "package.json");
    if (this.vol.existsSync(pkgJson)) {
      await syncPathToOPFS(this.vol, pkgJson);
    }
    // Recursively sync the entire node_modules subtree so every package file
    // (not just directory entries) is persisted and survives a page refresh.
    const nmDir = path.join(cwd, "node_modules");
    if (this.vol.existsSync(nmDir)) {
      await syncEntireVolumeToOPFS(this.vol, undefined, nmDir);
    }
  }

  // Called after install(single package) — syncs only the new packages so we
  // don't pay the cost of syncing all of node_modules on every add.
  private async syncNewPackagesToOPFS(
    newPkgs: string[],
    onProgress?: (msg: string) => void,
  ): Promise<void> {
    if (newPkgs.length === 0) return;
    try {
      const cwd = this.workingDir || "/";
      const nmDir = path.join(cwd, "node_modules");
      // Sync package.json if it exists
      const pkgJson = path.join(cwd, "package.json");
      if (this.vol.existsSync(pkgJson)) {
        await syncPathToOPFS(this.vol, pkgJson);
      }
      // Sync each newly added package directory recursively
      for (const pkgName of newPkgs) {
        const pkgDir = path.join(nmDir, pkgName);
        if (this.vol.existsSync(pkgDir)) {
          await syncEntireVolumeToOPFS(this.vol, undefined, pkgDir);
        }
      }
      // Sync the updated lock file
      const lockPath = path.join(nmDir, ".package-lock.json");
      if (this.vol.existsSync(lockPath)) {
        await syncPathToOPFS(this.vol, lockPath);
      }
      // Write an empty stamp to invalidate the manifest-based fast path.
      // This forces installFromManifest on next cold start to re-hydrate from
      // OPFS (which now contains the newly added packages) and skip any missing
      // packages via the "up to date" check.
      await writeRegistryMetadataToOPFS(
        INSTALL_STAMP_NAMESPACE,
        cwd,
        "",
      );
      onProgress?.("Synced new packages to OPFS");
    } catch (err) {
      const msg = err instanceof Error ? err.message : String(err);
      onProgress?.(`OPFS sync skipped: ${msg}`);
    }
  }

  private async patchManifest(
    depName: string,
    versionSpec: string,
    asDev: boolean,
  ): Promise<void> {
    const jsonPath = path.join(this.workingDir, "package.json");

    let manifest: Record<string, unknown> = {};
    if (this.vol.existsSync(jsonPath)) {
      manifest = JSON.parse(this.vol.readFileSync(jsonPath, "utf8"));
    }

    const section = asDev ? "devDependencies" : "dependencies";
    if (!manifest[section]) {
      manifest[section] = {};
    }
    (manifest[section] as Record<string, string>)[depName] = versionSpec;

    this.vol.writeFileSync(jsonPath, JSON.stringify(manifest, null, 2));
  }
}

// ---------------------------------------------------------------------------
// Convenience function
// ---------------------------------------------------------------------------

// One-shot install: `install("express@4.18.2", vol)`
export async function install(
  specifier: string,
  vol: MemoryVolume,
  flags?: InstallFlags,
): Promise<InstallOutcome> {
  const installer = new DependencyInstaller(vol);
  return installer.install(specifier, undefined, flags);
}

